INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Bleeding Darkness', 3, 'Evocation', 'Action', '60 feet', 'V, S, M (a vial of rare ink worth 50+ GP)', 'Concentration, up to 1 minute', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Warlock', 'Wizard']::TEXT[], 'You create an inky void in a 10-foot-radius Sphere at a point you can see above yourself within range. When you cast the spell, magical Darkness pours from the sphere, filling a 10-foot-radius, 40-foot-tall Cylinder originating from the Sphere until the start of your next turn. The Cylinder is Difficult Terrain, and no light—magical or otherwise—can illuminate the area. When the Darkness appears, each creature in the area must succeed on a Constitution saving throw or take 3d8 Cold damage and have the Blinded condition until the end of its next turn. A creature also makes this save when it enters the spell’s area for the first time on a turn or ends its turn there. A creature makes this save only once per turn. Until the spell ends, you can take a Magic action to move the Sphere up to 20 feet horizontally and cause the Sphere to pour magical Darkness until the start of your next turn. Using a Higher-Level Spell Slot. The damage increases by 1d8 for each spell slot level above 3.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Ectoplasmic Trail', 2, 'Necromancy', 'Bonus Action', 'Self', 'V, S', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Warlock']::TEXT[], 'You cloak yourself in spirits that leave ectoplasm in your wake until the end of your turn. While cloaked, you can move through occupied spaces as if they were Difficult Terrain, and moving doesn’t provoke Opportunity Attacks. If you end your turn in such a space, you are returned to the last unoccupied space you were in. While cloaked, whenever you enter the space of a creature, the creature becomes covered in ectoplasm until the end of your next turn. A creature covered in ectoplasm has its Speed reduced by 10 feet and takes 2d8 Necrotic damage at the start of its turn. A creature can be covered in ectoplasm only once during a turn. Using a Higher-Level Spell Slot. While cloaked, your Speed increases by 10 feet for each spell slot level above 2.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Abi-Dalzim''s Horrid Wilting', 8, 'Necromancy', 'Action', '150 feet', 'V, S, M (a bit of sponge)', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Sorcerer', 'Wizard']::TEXT[], 'You draw the moisture from every creature in a 30-foot Cube centered on a point within range. Each creature in that area makes a Constitution saving throw, taking 12d8 Necrotic damage on a failed save or half as much damage on a successful one. Constructs automatically succeed at the save, and Plant creatures automatically fail the save. Nonmagical plants in the area that aren’t creatures, such as trees and shrubs, wither and die instantly.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Ego Whip', 2, 'Enchantment', 'Reaction, which you take when a creature you can see within 30 feet of yourself makes a Charisma-based ability check or saving throw', '120 feet', 'V', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion']::TEXT[], 'The creature makes Charisma saving throw. On a failed save, the target must subtract 1d8 from the ability check or saving throw.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Enemies Abound', 3, 'Enchantment', 'Action', '120 feet', 'V, S', 'Concentration, up to 1 minute', 'UA9 - Psion Update (02.10.2025)', ARRAY['Bard', 'Psion', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'Choose a creature you can see within range. The target must succeed on an Intelligence saving throw or have the Frightened condition for the duration. While Frightened, the target loses the ability to distinguish friend from foe and is affected in the following ways:
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Homunculus Servant', 2, 'Conjuration', '1 hour or Ritual', '10 feet', 'V, S, M (a gem or crystal worth 100+ GP, which the spell consumes)', 'Instantaneous', 'Artificer UA (17.12.2024) and Eberron Updates UA (27.2.2025)', ARRAY['Artificer']::TEXT[], 'You summon a special homunculus in an unoccupied space within range. This creature uses the Homunculus Servant stat block. If you already have a homunculus from this spell, the homunculus is replaced by the new one. You determine the homunculus’s appearance, such as a mechanical-looking bird; winged vials; or miniature, animate cauldrons.
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Intellect Fortress', 3, 'Abjuration', 'Action', '30 Feet', 'V', 'Concentration, up to 1 hour', 'UA5 - The Psion 27.05.2025 and UA9 - Psion Update (02.10.2025)', ARRAY['Artificer', 'Bard', 'Psion', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'For the duration, one willing creature you can see within range has Resistance to Psychic damage, as well as Advantage on Intelligence, Wisdom, and Charisma saving throws.
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Life Siphon', 1, 'Evocation', 'Action', '120 feet', 'S', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion']::TEXT[], 'You fire an orb of psionic energy fueled by your life force at a creature you can see within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Psychic damage and you can expend one Hit Point Die to increase the damage by 1d10. Using a Higher-Level Spell Slot. The damage increases by 1d10 and the number of Hit Dice you can expend increases by one for each spell slot level above 1.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Life Inversion Field', 4, 'Abjuration', 'Action', 'Self', 'V, S', 'Concentration, up to 1 minute', 'UA9 - Psion Update (02.10.2025)', ARRAY['Cleric', 'Psion', 'Sorcerer']::TEXT[], 'An aura radiates from you in a 30-foot Emanation for the duration. When you create the aura, you regain 4d8 Hit Points. Whenever you regain Hit Points, you can choose a creature you can see in the aura and force it to make a Constitution saving throw. On a failed save, the creature takes Necrotic damage equal to half the amount of Hit Points you regained (round up). A creature makes this save only once per turn. Using a Higher-Level Spell Slot. The healing increase by 1d8 for each spell slot level above 4.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Mental Prison', 6, 'Illusion', 'Action', '60 feet', 'S', 'Concentration, up to 1 minute', 'UA9 - Psion Update (02.10.2025)', ARRAY['Bard', 'Psion', 'Sorcerer', 'Wizard']::TEXT[], 'You attempt to bind a creature within an illusory cell that only it perceives. One creature you can see within range must succeed on an Intelligence saving throw or take 8d10 Psychic damage and have the Charmed condition for the duration. On a successful save, the target takes half damage only and the spell ends. While Charmed, the target has the Restrained condition and perceives the area around its space as dangerous to it in some way you create. You might cause the target to perceive itself as being surrounded by fire, floating razors, or hideous maws filled with dripping teeth. Whatever form the illusion takes, the target can’t see or hear anything beyond it. If the target is moved from the illusion, makes a melee attack through it, or reaches any part of its body through it, the target takes 5d10 Psychic damage and the spell ends.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Psionic Blast', 6, 'Evocation', 'Action', 'Self', 'V, S, M', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Wizard']::TEXT[], 'You unleash a concussive burst of psionic energy. Each creature in a 60-foot Cone originating from you makes an Intelligence saving throw. On a failed save, the creature takes 6d8 Psychic damage and has the Stunned condition until the start of your next turn. On a successful save, the creature takes half as much damage only. Using a Higher-Level Spell Slot. The damage increases by 1d8 for each spell slot level above 6.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Psychic Scream', 9, 'Enchantment', 'Action', '90 feet', 'S', 'Instantanious', 'UA5 - The Psion (27.05.2025) and UA9 - Psion Update (02.10.2025)', ARRAY['Bard', 'Psion', 'Sorcerer', 'Warlock']::TEXT[], 'You unleash the power of your mind to blast the intellect of up to ten creatures of your choice that you can see within range. Creatures that have an Intelligence score of 2 or lower are unaffected. Each target must make an Intelligence saving throw. On a failed save, a target takes 14d6 Psychic damage and has the Stunned condition. On a successful save, a target takes half as much damage only. If the target is reduced to 0 Hit Points by this damage, its head explodes, assuming it has one. At the end of each of its turns, the Stunned target repeats the save, ending the condition on itself on a success.', NULL, TRUE, ARRAY['spell', 'ua', 'ua5', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Raulothim''s Psychic Lance', 4, 'Enchantment', 'Action', '120 feet', 'V', 'Instantaneous', 'UA5 - The Psion (27.05.2025) and UA9 - Psion Update (02.10.2025)', ARRAY['Bard', 'Psion', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You unleash a shimmering lance of psychic power from your forehead at a creature that you can see within range. Alternatively, you can utter a creature’s name (a pseudonym, title, or nickname doesn’t work). If the named target is within range, it becomes the spell’s target even if you can’t see it. If the named target isn’t within range or you use an invalid name, the lance dissipates without effect. The target must make an Intelligence saving throw. On a failed save, the target takes 7d6 Psychic damage and has the Incapacitated condition until the start of your next turn. On a successful save, the target takes half as much damage only. Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 4.', NULL, TRUE, ARRAY['spell', 'ua', 'ua5', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Summon Astral Entity', 3, 'Conjuration', 'Action', '90 feet', 'V, S, M (a gem or crystal worth 300+ GP)', 'Concentration, up to 1 hour', 'UA5 - The Psion (27.05.2025) and UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You call forth the spirit of a psionic entity. It manifests in an unoccupied space that you can see within range and uses the Psionic Spirit stat block. When you cast the spell, choose Crystal Entity, Ectoplasmic Entity, or Ghostly Entity. The creature resembles an astral entity of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Using a Higher-Level Spell Slot. Use the spell slot’s level for the spell’s level in the stat block.', NULL, TRUE, ARRAY['spell', 'ua', 'ua5', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Tasha''s Mind Whip (UA5)', 2, 'Enchantment', 'Action', '90 feet', 'V', 'Instantaneous', 'UA5 - The Psion (27.05.2025)', ARRAY['Psion', 'Sorcerer', 'Wizard']::TEXT[], 'You psychically lash out at one creature you can see within range. The target must make an Intelligence saving throw. On a failed save, the target takes 3d6 Psychic damage, and it can’t make Opportunity Attacks until the end of its next turn. Moreover, on its next turn, it can take either an action or a Bonus Action, not both. On a successful save, the target takes half as much damage only. Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 2.', NULL, FALSE, ARRAY['spell', 'ua', 'ua5']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Tasha''s Mind Whip (UA9)', 2, 'Enchantment', 'Action', '90 feet', 'V', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Sorcerer', 'Wizard']::TEXT[], 'You psychically lash out at one creature you can see within range. The target must make an Intelligence saving throw. On a failed save, the target takes 3d6 Psychic damage and can’t make Opportunity Attacks until the end of its next turn. On its next turn, it must choose whether it gets a move, an action, or a Bonus Action; it gets only one of the three. On a successful save, the target takes half as much damage only. Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 2.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Telekinetic Crush', 3, 'Transmutation', 'Action', '120 feet', 'V', 'Instantaneous', 'UA5 - The Psion (27.05.2025) and UA9 - Psion Update (02.10.2025)', ARRAY['Psion', 'Sorcerer', 'Warlock']::TEXT[], 'You create a field of crushing telekinetic force in a 30-foot Cube within range. Each creature in the area makes a Strength saving throw. On a failed save, a target takes 5d6 Force damage and has the Prone condition. On a successful save, a target takes half as much damage only. Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 3.', NULL, TRUE, ARRAY['spell', 'ua', 'ua5', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Telekinetic Fling (UA5)', 0, 'Evocation', 'Action', '60 feet', 'V, M (an Arrow, Bolt, Bullet, or Needle worth at least 1 CP)', 'Instantaneous', 'UA5 - The Psion (27.05.2025)', ARRAY['Psion']::TEXT[], 'You brandish the ammunition used to cast this spell and fire it at a creature within range using psionic energy. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Force damage, and the ammunition is destroyed. Cantrip Upgrade. The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).', NULL, FALSE, ARRAY['spell', 'ua', 'ua5']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Telekinetic Fling (UA9)', 0, 'Evocation', 'Action', '60 feet', 'S', 'Instantaneous', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion']::TEXT[], 'Choose one nonmagical object weighing 1 to 5 pounds within 10 feet of you that isn’t being worn or carried to wreathe in psionic energy and fire at a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Force damage. On a hit or miss, the object falls to the ground undamaged. Cantrip Upgrade. The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Thought Form', 6, 'Transmutation', 'Bonus Action', 'Self', 'V, M (brain matter in a vessel worth 500+ GP)', 'Concentration, up to 1 minute', 'UA9 - Psion Update (02.10.2025)', ARRAY['Psion']::TEXT[], 'You briefly transform into a psionic spirit. You gain the following benefits until the spell ends. Ghostly Form. You have Immunity to Poison and Psychic damage, and you have Immunity to the Exhaustion condition. Incorporeal Movement. You have a Fly Speed of 60 feet and can hover. You can move through occupied spaces as if they were Difficult Terrain. If you end your turn in such a space, you take 1d10 Force damage. If the spell ends in such a space, you are returned to the last unoccupied space you were in. Psionic Recharge. As a Magic action, you can touch a creature (which can be yourself) and roll 1d6. The creature regains one expended spell slot, the level of which equals half the number rolled (round up) or lower. Once a creature regains a spell slot from this spell, that creature can’t do so again until it finishes a Long Rest.', NULL, FALSE, ARRAY['spell', 'ua', 'ua9']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Aberrant Dragonmark', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Aberrant Fortitude","description":"When you make a Constitution saving throw, you can roll 1d4 and add the number rolled to the save. You can use this benefit a number of times equal to your Proficiency Bonus and regain all expended uses when you finish a Long Rest."},{"name":"Aberrant Magic","description":"You know one cantrip of your choice from the Sorcerer spell list. Also, choose a level 1 spell from that spell list. You always have that spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Short or Long Rest. You can also cast this spell using any spell slots you have. Constitution is your spellcasting ability for this spell."},{"name":"Aberrant Surge","description":"When you cast the level 1 spell from this feat, you can expend one of your Hit Point Dice and roll it. If you roll an even number, you gain a number of Temporary Hit Points equal to the number rolled. If you roll an odd number, one creature within 30 feet of you (not including you) takes Force damage equal to the number rolled. If no other creatures are in range, you take the damage."}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Healing', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Finding', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Hunter’s Intuition","description":"When you make a Wisdom (Perception or Survival) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Finder’s Magic","description":"You always have the Hunter’s Mark spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat). When you reach character level 3, you also always have the Locate Object spell prepared and can cast it the same way."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Finding Spells table are added to that feature’s spell list."},{"name":"Mark of Finding Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Handling', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Wild Intuition","description":"When you make an Intelligence (Nature) or Wisdom (Animal Handling) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Primal Connection","description":"You always have the Animal Friendship and Speak with Animals spells prepared. You can cast each spell once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast these spells using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"The Bigger They Are","description":"When you reach character level 3, you can target a Monstrosity when you cast Animal Friendship or Speak with Animals if the creature’s Intelligence score is 3 or lower."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Handling Spells table are added to that feature’s spell list."},{"name":"Mark of Handling Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Detection', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Deductive Intuition","description":"When you make a Wisdom (Insight or Perception) check, you can roll 1d4 and add the number rolled to the ability check. Magical Detection. You always have the Detect Magic and Detect Poison and Disease spells prepared. You can cast each spell once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast these spells using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat). When you reach character level 3, you also always have the See Invisibility spell prepared and can cast it the same way."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Detection Spells table are added to that feature’s spell list."},{"name":"Mark of Detection Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Hospitality', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Ever Hospitable","description":"When you make a Charisma (Persuasion) check or an ability check using Brewer’s Supplies or Cook’s Utensils, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Innkeeper’s Magic","description":"You know the Prestidigitation cantrip. You also always have the Purify Food and Drink and Unseen Servant spells prepared. You can cast each spell once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast these spells using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Hospitality Spells table are added to that feature’s spell list."},{"name":"Mark of Hospitality Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Passage', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Courier’s Speed","description":"Your Speed increases by 5 feet."},{"name":"Intuitive Motion","description":"When you make a Strength (Athletics) or Dexterity (Acrobatics) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Magical Passage","description":"You always have the Misty Step spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Passage Spells table are added to that feature’s spell list."},{"name":"Mark of Passage Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Making', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)', '[{"name":"Artisan’s Intuition","description":"When you make an Intelligence (Arcana) check or an ability check using Artisan’s Tools, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Spellsmith","description":"You know the Mending cantrip. You also always have the Magic Weapon spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Making Spells table are added to that feature’s spell list."}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Scribing', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Gifted Scribe","description":"When you make an Intelligence (History) check or an ability check using Calligrapher’s Supplies, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Scribe’s Insight","description":"You know the Message cantrip. You also always have the Comprehend Languages spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat). When you reach character level 3, you also always have the Magic Mouth spell prepared and can cast it the same way."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Scribing Spells table are added to that feature’s spell list."},{"name":"Mark of Scribing Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Sentinel', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Sentinel’s Intuition","description":"When you make a Wisdom (Insight or Perception) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Guardian’s Shield","description":"You always have the Shield spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Vigilant Guardian","description":"When a creature you can see within 5 feet of you is hit by an attack roll, you can take a Reaction to swap places with that creature, and you are hit by the attack instead. Once you use this feature, you can’t do so again until you finish a Long Rest."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Sentinel Spells table are added to that feature’s spell list."},{"name":"Mark of Sentinel Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Shadow', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Cunning Intuition","description":"When you make a Dexterity (Stealth) or Charisma (Performance) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Shape Shadows","description":"You know the Minor Illusion cantrip. You also always have the Invisibility spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Shadow Spells table are added to that feature’s spell list."},{"name":"Mark of Shadow Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Storm', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Windwright’s Intuition","description":"When you make a Dexterity (Acrobatics) check or an ability check using Navigator’s Tools, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Storm’s Boon","description":"You have Resistance to Lightning damage."},{"name":"Storm Magic","description":"You know the Thunderclap cantrip. When you reach character level 3, you also always have the Gust of Wind spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Storm Spells table are added to that feature’s spell list."},{"name":"Mark of Storm Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Aberrant Mark', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Aberrant Dragonmark Feat)', '[{"name":"Ability Score Increase","description":"Increase your Constitution score by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Aberrant Fortitude benefit of your Aberrant Dragonmark feat, you can roll 1d6 instead of 1d4."},{"name":"Mark of Inspiration","description":"When you cast a cantrip, you can expend one of your Hit Point Dice and roll it. You gain a number of Temporary Hit Points equal to the number rolled, and one creature of your choice within 30 feet of you (not including you) takes Force damage equal to the number rolled. You can use this benefit a number of times equal to your Constitution modifier (minimum of once), and you regain all expended uses when you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Warding', 'Playtest Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Warder’s Intuition","description":"When you make an Intelligence (Investigation) check or an ability check using Thieves’ Tools, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Wards and Seals","description":"You always have the Alarm and Mage Armor spells prepared. You can cast each spell once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast these spells using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat). When you reach character level 3, you also always have the Arcane Lock spell prepared and can cast it the same way."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Warding Spells table are added to that feature’s spell list."},{"name":"Mark of Warding Spells","description":""}]'::jsonb, TRUE, ARRAY['dragonmarkfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Detection', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Detection Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Deductive Intuition benefit of your Mark of Detection feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Detection","description":"When you cast See Invisibility, you can modify it so that for the duration of the spell, you have Advantage on Initiative rolls and enemies that roll Initiative within 30 feet of you can’t gain Advantage on the roll. Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Healing', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Healing Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Medical Intuition benefit of your Mark of Healing feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Healing","description":"When you cast Cure Wounds and roll dice to determine the number of Hit Points restored, you can treat any 1 or 2 on a roll as a 3."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Finding', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Finding Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Hunter’s Intuition benefit of your Mark of Finding feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Finding","description":"When you cast Hunter’s Mark, you can modify it so that the target can’t benefit from the Invisible condition for the duration of the spell. Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Handling', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Handling Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Wild Intuition benefit of your Mark of Handling feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Handling","description":"While mounted, immediately after you hit a target within 5 feet of your mount with a melee attack roll, your mount can take a Reaction to move up to its Speed or take the Attack action to make one attack only (your choice)."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Hospitality', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Hospitality Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Ever Hospitable benefit of your Mark of Hospitality feat, you can roll 1d6 instead of 1d4."},{"name":"Inspired Hospitality","description":"When you cast Purify Food and Drink, you can modify the spell so that each creature of your choice within 30 feet of you is magically refreshed. Each affected creature’s Exhaustion level is reduced by 1, and the creature gains Temporary Hit Points equal to your Proficiency Bonus plus your Intelligence, Charisma, or Wisdom modifier (choose when you select this feat). Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Making', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Making Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Artisan’s Intuition benefit of your Mark of Making feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Making","description":"When you cast Magic Weapon, you can modify the spell so that the first time you attack with the weapon on each of your turns, you can transfer some or all of the weapon’s bonus to your Armor Class. For example, if the bonus is +2, you could reduce the bonus to your attack rolls and damage rolls to +1 and gain a +1 bonus to Armor Class. The adjusted bonus remains in effect until the start of your next turn, although you must hold the weapon to gain a bonus to AC from it. Once you modify the spell using this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Passage', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Passage Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Intuitive Motion benefit of your Mark of Passage feat, you can roll 1d6 instead of 1d4."},{"name":"Inspired Passage","description":"When you cast Misty Step, you can modify the spell so that you can bring one willing creature you are touching with you. That creature teleports to an unoccupied space of your choice within 5 feet of your destination space. Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Shadow', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Shadow Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Cunning Intuition benefit of your Mark of Shadow feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Shadow","description":"When you cast Invisibility on yourself, you can modify the spell to also affect one willing creature within 5 feet of yourself. The Invisible condition ends immediately for an affected creature after it makes an attack roll, deals damage, or casts a spell. Once you modify the spell with this benefit, you can’t do so again until you finish Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Sentinel', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Sentinel Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Sentinel’s Intuition benefit of your Mark of Sentinel feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Sentinel","description":"When you cast Shield, you can modify the spell so that it magically marks a creature you can see within 30 feet of you until the end of its next turn. While marked, the target must spend 2 feet of movement for every 1 foot they move away from you."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Scribing', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Scribing Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Gifted Scribe benefit of your Mark of Scribing feat, you can roll 1d6 instead of 1d4."},{"name":"Inspired Scribing","description":"When you cast Comprehend Languages, you can modify the spell to cause a sigil to appear in the air above a creature you can see within 30 feet of yourself, which lasts for the duration of the spell. While the sigil persists, your enemies within 30 feet of the creature must spend 2 feet of movement for every 1 foot they move closer to that creature. The sigil disappears if the creature makes an attack roll, casts a spell, or deals damage."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Storm', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Storm Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Windwright’s Intuition benefit of your Mark of Storm feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Storm","description":"When you cast Gust of Wind, you modify the spell so that you gain a Fly Speed equal to half your Speed (round down) for the duration of the spell. Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Atmokinesis', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Lightning Jolt","description":"You gain the following benefits.  Once per turn when you cast a spell or hit with an attack roll and deal Bludgeoning, Piercing, Slashing, or Psychic damage, you can change the damage type to Lightning damage. Psionic Talent. You know the Shocking Grasp cantrip. You also always have the Fog Cloud spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat). When you reach character level 3, you also always have the Gust of Wind spell prepared and can cast it the same way."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Clairsentience', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Minor Foreknowledge","description":"You gain the following benefits.  When you take the Search action, you can give yourself Advantage on any ability check made as part of that action. You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest. Psionic Talent. You know the Guidance cantrip. You also always have the Detect Evil and Good spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat). When you reach character level 3, you also always have the See Invisibility spell prepared and can cast it the same way."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Warding', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Warding Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Warder’s Intuition benefit of your Mark of Warding feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Warding","description":"When you cast Mage Armor on yourself, you can modify the spell to also affect one willing creature you can see within 30 feet of yourself. Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Biokinesis', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Bend Life Energy","description":"You gain the following benefits.  When a spell you cast restores Hit Points to a creature, you can roll 1d4 and add the number rolled to the total Hit Points restored. You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest. Psionic Talent. You know the Spare the Dying cantrip. You also always have the Healing Word spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat). When you reach character level 3, you also always have the Arcane Vigor spell prepared and can cast it the same way."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Potent Dragonmark', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Any Dragonmark Feat)', '[{"name":"Ability Score Increase","description":"Increase the spellcasting ability score used by your Dragonmark feat by 1, to a maximum of 20."},{"name":"Dragonmark Preparation","description":"You always have the spells on your Dragonmark feat’s Spells of the Mark list (if any) prepared."},{"name":"Dragonmark Spellcasting","description":"You have one spell slot to cast the spells granted by your Dragonmark feat. The spell slot’s level is one-half your level (round up), to a maximum of level 5. You regain the expended slot when you finish a Short or Long Rest. You can use this spell slot to cast only a spell that you have prepared because of your Dragonmark feat or the Dragonmark Preparation benefit of this feat."}]'::jsonb, TRUE, ARRAY['generalfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Cryokinesis', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Ice Manipulation","description":"You gain the following benefits.  Once per turn when you cast a spell or hit with an attack roll and deal Bludgeoning, Piercing, Slashing, or Psychic damage, you can change the damage type to Cold damage. Psionic Talent. You know the Ray of Frost cantrip. You also always have the Armor of Agathys and Ice Knife spells prepared. You can cast each spell once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast these spells using any spell slots you have. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat)."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Empath', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Emotional Sense","description":"You gain the following benefits.  When you take the Influence action, you can give yourself Advantage on any ability check made as part of that action. You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest. Psionic Talent. You always have the Charm Person spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. When you cast the spell, it requires no Verbal components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you select this feat). When you reach character level 3, you also always have the Calm Emotions spell prepared and can cast it the same way."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Flesh Morpher', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Flexible Flesh","description":"You gain the following benefits.  When you make a Dexterity (Acrobatics or Sleight of Hand) check, you gain a bonus equal to your Intelligence modifier (minimum of +1). You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest. Psionic Talent. You always have the Longstrider spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. When you cast the spell, it requires no Verbal components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you select this feat). When you reach character level 3, you also always have the Alter Self spell prepared and can cast it the same way."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mind Whisperer', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Limited Telepathy","description":"You gain the following benefits.  As a Magic action, choose one creature you can see within 120 feet of yourself. You form a telepathic connection to that creature. For 1 hour, you and the chosen creature can communicate telepathically with each other while within 120 feet of each other. To understand each other, you each must mentally use a language the other knows. Once you use this benefit, you can’t do so again until you finish a Short or Long Rest. Psionic Talent. You know the Mind Sliver cantrip. You also always have the Dissonant Whispers spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat)."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Psi Trickster', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Cunning Mind","description":"You gain the following benefits.  When you make a Charisma (Deception or Persuasion) check, you gain a bonus equal to your Intelligence modifier (minimum bonus of +1). You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest. Psionic Talent. You know the Minor Illusion cantrip. You also always have the Disguise Self spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat)."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Psykineticist', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Psi Boost","description":"You gain the following benefits.  When you take the Dash action, you can increase your Speed by 10 feet until the start of your next turn. You can do this a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest. Psionic Talent. You know the Telekinetic Fling cantrip (included in this UA). You also always have the Thunderwave spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. When you cast these spells, they require no Verbal components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat)."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Pyrokinesis', 'Playtest Feat', NULL, 'Wild Talent Feat (Prerequisite: Can’t Have Another Wild Talent Feat)', '[{"name":"Firestarter","description":"You gain the following benefits.  Once per turn when you cast a spell or hit with an attack roll and deal Bludgeoning, Piercing, Slashing, or Psychic damage, you can change the damage type to Fire damage. Psionic Talent. You know the Produce Flame cantrip. You also always have the Burning Hands spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. When you cast these spells, they require no Verbal or Material components, and Intelligence, Wisdom, or Charisma is your spellcasting ability for them (choose when you select this feat). When you reach character level 3, you also always have the Scorching Ray spell prepared and can cast it the same way."}]'::jsonb, FALSE, ARRAY['ua', 'ua5', 'wildtalentfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Death Knight Ascension', 'Playtest Feat', NULL, 'Path of the Death Knight Feat (Prerequisite: Level 12+, two Path of the Death Knight Feats)
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Death Knight Initiate', 'Playtest Feat', NULL, 'Path of the Death Knight Feat (Prerequisite: Level 4+, Weapon Mastery Feature)', '[{"name":"Ability Score Increase","description":"Increase your Strength or Charisma score by 1, to a maximum of 20."},{"name":"Death Points","description":"Your dedication to the path of the Death Knight gives you access to profane powers of undeath. Your ability to use such powers is represented by Death Points. You have a number of Death Points equal to your Proficiency Bonus. You regain all expended Death Points when you finish a Long Rest. You can expend Death Points to use certain Path of the Death Knight benefits. This feat gives you one such benefit: Dread Strike."},{"name":"Dread Strike","description":"You always have the Wrathful Smite spell prepared. Charisma is your spellcasting ability for this spell. You can cast it without expending a spell slot by expending 1 Death Point. When you expend Death Points to cast Wrathful Smite, the target has Disadvantage on Wisdom saving throws to avoid or end the spell’s effect. You can also cast the spell using any spell slots you have."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Deathly Presence', 'Playtest Feat', NULL, 'Path of the Death Knight Feat (Prerequisite: Level 8+, Death Knight Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Strength, Constitution, or Charisma score by 1, to a maximum of 20."},{"name":"Awful Presence","description":"You always have the Fear spell prepared. Charisma is your spellcasting ability for this spell. You can cast it without expending a spell slot by expending 1 Death Point. You can also cast the spell using any spell slots you have. When you expend Death Points to cast Fear, you deal 7 (2d6) Psychic damage to each creature that fails its saving throw against the spell, in addition to the spell’s normal effects."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Harbinger of Doom', 'Playtest Feat', NULL, 'Path of the Death Knight Feat (Prerequisite: Death Knight Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Strength, Constitution, or Charisma score by 1, to a maximum of 20."},{"name":"Ill Omen","description":"You always have the Bane spell prepared. Charisma is your spellcasting ability for this spell. You can cast it without expending a spell slot by expending 1 Death Point. You can also cast the spell using any spell slots you have. When you expend Death Points to cast Bane, affected targets subtract 1d6 from attack rolls and saving throws instead of 1d4."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Dread Authority', 'Playtest Feat', NULL, 'Path of the Death Knight Feat (Prerequisite: Death Knight Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Constitution or Charisma score by 1, to a maximum of 20."},{"name":"Dread Command","description":"You always have the Command spell prepared. Charisma is your spellcasting ability for this spell. You can cast it without expending a spell slot by expending 1 Death Point. You can also cast the spell using any spell slots you have. When you expend Death Points to cast Command, Undead targeted by it have Disadvantage on the saving throw against the spell."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Unholy Steed', 'Playtest Feat', NULL, 'Path of the Death Knight Feat (Prerequisite: Level 8+, Death Knight Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Strength or Constitution score by 1, to a maximum of 20."},{"name":"Spectral Steed","description":"You always have the Find Steed spell prepared. Charisma is your spellcasting ability for this spell. You can cast it without expending a spell slot by expending 1 Death Point. When you expend Death Points to cast Find Steed, the summoned steed is a Fiend, and targets you choose have Disadvantage on the Wisdom saving throw against its Fell Glare. You can also cast the spell using any spell slots you have."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Arcane Restoration', 'Playtest Feat', NULL, 'Path of the Lich Feat (Prerequisite: Lich Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Essence Rejuvenation","description":"When you use Soul Siphon to consume a soul, you can choose one or more expended spell slots to recover. The spell slots can have a combined level equal to no more than 4. Once you use this feature, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Lich Ascension', 'Playtest Feat', NULL, 'Path of the Lich Feat (Prerequisite: Level 12+, at least two Path of the Lich Feats)
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Lich Initiate', 'Playtest Feat', NULL, 'Path of the Lich Feat (Prerequisite: Level 4+, Spellcasting or Pact Magic Feature)
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Undead Grasp', 'Playtest Feat', NULL, 'Path of the Lich Feat (Prerequisite: Lich Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Paralyzing Touch","description":"You know the Chill Touch cantrip. If you already know it, you learn another cantrip of your choice. Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you select this feat). When you deal damage with Chill Touch, you can expend a level 1+ spell slot to attempt to paralyze the target. The target takes an extra 1d10 Necrotic damage per level of the spell slot expended and must succeed on a Constitution saving throw against your spell save DC or have the Paralyzed condition until the start of your next turn."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Transfer Life', 'Playtest Feat', NULL, 'Path of the Lich Feat (Prerequisite: Lich Initiate Feat)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Soul Transference","description":"When you use Soul Siphon to consume a soul, you can choose a creature within 60 feet of yourself to gain Temporary Hit Points equal to your Proficiency Bonus plus your spellcasting ability modifier (minimum of 1 Temporary Hit Point)."}]'::jsonb, FALSE, ARRAY['pathofvillainyfeat', 'ua', 'ua12']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Siberys', 'Playtest Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+, Eberron Campaign)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Aberrant Magic","description":"Choose a spell of any level from the Sorcerer spell list or a spell from the Siberys Dragonmarks table. You always have that spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Short or Long Rest. You can also cast this spell using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you gain this feat)."},{"name":"Siberys Dragonmarks","description":""}]'::jsonb, TRUE, ARRAY['epicboonfeat', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.classes (name, source, description, primary_ability, saving_throws, hit_dice, weapon_proficiencies, armor_proficiencies, tool_proficiencies, skill_proficiencies, class_table, features, legacy, tags) VALUES ('Artificer', 'Artificer UA (17.12.2024)', 'A Magical Crafter and an Inventor of Wonders Masters of invention, Artificers use ingenuity and magic to unlock extraordinary capabilities in objects. They see magic as a complex system waiting to be decoded and then harnessed in their spells and inventions. You can find everything you need to play one of these inventors in the next few sections.', 'Intelligence', ARRAY['Constitution', 'Intelligence']::TEXT[], 'd8', ARRAY['Simple weapons']::TEXT[], ARRAY['Light', 'Medium armor', 'Shields']::TEXT[], ARRAY['Thieves’ Tools', 'Tinker’s Tools', 'one type of Artisan’s Tools of your choice']::TEXT[], ARRAY['Choose 2: Arcana', 'History', 'Investigation', 'Medicine', 'Nature', 'Perception', 'or Sleight of Hand']::TEXT[], '{"headers":["Level","Proficiency Bonus","Class Features"],"rows":[["1","+2","Magical Tinkering, Spellcasting"],["2","+2","Replicate Magic Item"],["3","+2","Artificer Subclass, Right Tool for the Job"],["4","+2","Ability Score Improvement"],["5","+3","Subclass feature"],["6","+3","Magic Item Tinker"],["7","+3","Flash of Genius"],["8","+3","Ability Score Improvement"],["9","+4","Subclass Feature"],["10","+4","Magic Item Adept"],["11","+4","Spell-Storing Item"],["12","+4","Ability Score Improvement"],["13","+5","-"],["14","+5","Magic Item Savant"],["15","+5","Subclass Feature"],["16","+5","Ability Score Improvement"],["17","+6","-"],["18","+6","Magic Item Master"],["19","+6","Epic Boon"],["20","+6","Soul of Artifice"]]}'::jsonb, '[{"name":"Magical Tinkering","level":1,"description":"\n| Ball Bearings | Net |\n| --- | --- |\n| Basket | Oil |\n| Bedroll | Paper |\n| Bell | Parchment |\n| Blanket | Pole |\n| Block and Tackle | Pouch |\n| Bucket | Rope |\n| Caltrops | Sack |\n| Candle | Shovel |\n| Crowbar | String |\n| Flask | Tinderbox |\n| Jug | Torch |\n| Lamp | Vial |\n\n\n\nSee the rules for the item in the Player’s Handbook. The item vanishes after 1 hour.\n\nYou can use this feature a number of times equal to your Intelligence modifier (minimum of once), and you regain all expended uses when you finish a Long Rest."},{"name":"Spellcasting","level":1,"description":"You have learned how to channel magical energy through objects. See the Player’s Handbook for the rules on spellcasting. The information below details how you use those rules with Artificer spells, which appear in the Artificer spell list later in the class’s description.\n\nTools Required. You produce your Artificer spells through tools. You can use Thieves’ Tools, Tinker’s Tools, or another kind of Artisan’s Tools with which you have proficiency as a Spellcasting Focus, and you must have one of those focuses in hand when you cast an Artificer spell (meaning the spell has an “M” component when you cast it).\n\nCantrips. You know two Artificer cantrips of your choice. Acid Splash and Prestidigitation are recommended.\n\nWhenever you finish a Long Rest, you can replace one of your cantrips from this feature with another Artificer cantrip of your choice.\n\nWhen you reach Artificer levels 10 and 14, you learn another Artificer cantrip of your choice, as shown in the Cantrips column of the Artificer Features table.\n\nSpell Slots. The Artificer Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended spell slots when you finish a Long Rest.\n\nPrepared Spells of Level 1+. You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose two level 1 Artificer spells. Cure Wounds and Grease are recommended.\n\nThe number of spells on your list increases as you gain Artificer levels, as shown in the Prepared Spells column of the Artificer Features table. Whenever that number increases, choose additional Artificer spells until the number of spells on your list matches the number on the table. The chosen spells must be of a level for which you have spell slots. For example, if you’re a level 5 Artificer, your list of prepared spells can include six Artificer spells of levels 1 and 2 in any combination.\n\nIf another Artificer feature gives you spells that you always have prepared, those don’t count against the number of spells you can prepare with this feature, but those spells otherwise count as Artificer spells for you.\n\nChanging Your Prepared Spells. Whenever you finish a Long Rest, you can change your list of prepared spells, replacing any of the spells there with other Artificer spells for which you have spell slots.\n\nSpellcasting Ability. Intelligence is your spellcasting ability for your Artificer spells."},{"name":"Replicate Magical Item","level":2,"description":"You have learned arcane plans that you use to make magic items.\n\nPlans Known. When you gain this feature, choose four plans to learn from the Magic Item Plans (Artificer Level 2+) table (see the Dungeon Master’s Guide for the items’ descriptions). Bag of Holding, Cap of Water Breathing, Sending Stones, and Wand of the War Mage +1 are recommended. Whenever you gain an Artificer level, you can replace one of the plans you know with a new plan for which you qualify.\n\nYou learn another plan of your choice when you reach certain Artificer levels, as shown in the Plans Known column of the Artificer Features table.\n\nCreating an Item. When you finish a Long Rest, you can create one or two different magic items if you have Tinker’s Tools in hand. Each item is based on one of the plans you know for this feature.\n\nIf a created item requires Attunement, you can attune yourself to it the instant you create it. If you decide to attune to the item later, you must do so using the normal process for Attunement.\n\nWhen you reach certain Artificer levels specified in the Magic Items column of the Artificer Features table, the number of magic items you can create at the end of a Long Rest increases. Each item you create must be based on a different plan you know.\n\nIf you try to exceed your maximum number of magic items for this feature, the oldest item vanishes, and then the new item appears.\n\nDuration. A magic item created by this feature functions exactly like the normal magic item, except its magic isn’t permanent. When you die, the magic item vanishes after 1d4 of days.\n\nIf an item that you created with this feature is a container, such as a Bag of Holding, and it vanishes, its contents harmlessly appear in and around its space.\n\n\n| Magic Item Plan | Attunement |\n| --- | --- |\n| Alchemy Jug | No |\n| Bag of Holding | No |\n| Cap of Water Breathing | No |\n| Common magic item that isn’t a Potion, a Scroll, or cursed (you can learn this option multiple times and must select a different item each time; each item selected counts as a different plan) | Varies |\n| Goggles of Night | No |\n| Rope of Climbing | No |\n| Sending Stones | No |\n| Shield +1 | No |\n| Wand of Magic Detection | No |\n| Wand of Secrets | No |\n| Wand of the War Mage +1 | Yes |\n| Weapon +1 | No |\n\n\n\n\n| Magic Item Plan | Attunement |\n| --- | --- |\n| Armor +1 | No |\n| Boots of Elvenkind | No |\n| Cloak of Elvenkind | Yes |\n| Cloak of the Manta Ray | No |\n| Eyes of Charming | Yes |\n| Gloves of Thievery | No |\n| Lantern of Revealing | No |\n| Pipes of Haunting | No |\n| Uncommon Armor, Wand, or Weapon that isn’t cursed (you can learn this option multiple times and must select a different item each time; each item selected counts as a different plan) | Varies |\n\n\n\n\n| Magic Item Plan | Attunement |\n| --- | --- |\n| Uncommon Ring or Wondrous Item that isn’t cursed (you can learn this option multiple times and must select a different item each time; each item selected counts as a different plan) | Varies |\n\n\n\n\n| Magic Item Plan | Attunement |\n| --- | --- |\n| Rare Armor, Ring, Wand, Weapon, or Wondrous Item that isn’t cursed (you can learn this option multiple times and must select a different item each time; each item selected counts as a different plan) | Varies |\n\n"},{"name":"Artificer Subclass","level":3,"description":"You gain an Artificer subclass of your choice. The Alchemist, Armorer, Artillerist, and Battle Smith subclasses are detailed after this class’s description. A subclass is a specialization that grants you features at certain Artificer levels. For the rest of your career, you gain each of your subclass’s features that are of your Artificer level or lower.\n\n### Artificer Subclasses\n\nAlchemist\nArmorer\nArtillerist\nBattle Smith"},{"name":"Right Tool For The Job","level":3,"description":"The list of items you can create with Magical Tinkering now includes Artisan’s Tools, which are described in the Player’s Handbook."},{"name":"Ability Score Improvement","level":4,"description":"You gain the Ability Score Improvement feat or another feat of your choice for which you qualify.\n\nYou gain this feature again at Artificer levels 8, 12, and 16."},{"name":"Magic Item Tinker","level":6,"description":"Your Replicate Magic Item feature improves as follows:\n\nDrain Magic Item. As a Bonus Action, you can touch a magic item within 5 feet of yourself that you created with Replicate Magic Item and cause the item to vanish, converting its magical energy into a spell slot. The slot is level 1 if the item is Common or level 2 if the item is Uncommon or Rare. Once you use this feature, you can’t do so again until you finish a Long Rest. Any spell slot you create with this feature vanishes when you finish a Long Rest.\n\nExpanded Replication. When you learn a plan for your Replicate Magic Item feature, you can now also choose from the Magic Item Plans (Artificer Level 6+) table."},{"name":"Flash of Genius","level":7,"description":"When you or a creature you can see within 30 feet of you fails an ability check or a saving throw, you can take a Reaction to add a bonus to the roll, potentially causing it to succeed. The bonus equals your Intelligence modifier.\n\nYou can take this Reaction a number of times equal to your Intelligence modifier (minimum of once). You regain all expended uses when you finish a Long Rest."},{"name":"Magic Item Adept","level":10,"description":"You’ve achieved a profound understanding of how to use and make magic items, granting you the following benefits:\n\nAdditional Attunement. You can attune to up to four magic items at once rather than three.\n\nExpanded Replication. When you learn a plan for your Replicate Magic Item feature, you can now also choose from the Magic Item Plans (Artificer Level 10+) table."},{"name":"Spell-Storing Item","level":11,"description":"Whenever you finish a Long Rest, you can touch one Simple or Martial weapon or one item that you can use as a Spellcasting Focus, and you store a spell in it, choosing a level 1, 2, or 3 Artificer spell that has a casting time of an action (you needn’t have the spell prepared).\n\nWhile holding the object, a creature can take an action to produce the spell’s effect from it, using your spellcasting ability modifier. If the spell requires Concentration, the creature must concentrate. The spell stays in the object until it’s been used a number of times equal to twice your Intelligence modifier (minimum of twice) or until you use this feature again to store a spell in an object."},{"name":"Magic Item Savant","level":14,"description":"Your skill with magic items deepens, granting you the following benefits:\nAdditional Attunement. You can attune to up to five magic items at once rather than three.\n\nExpanded Replication. When you learn a plan for your Replicate Magic Item feature, you can now also choose from the Magic Item Plans (Artificer Level 14+) table. You can have no more than three Rare items created by Replicate Magic Item at a time."},{"name":"Magic Item Master","level":18,"description":"You can now attune to up to six magic items at once rather than three."},{"name":"Epic Boon","level":19,"description":"You gain an Epic Boon feat or another feat of your choice for which you qualify. Boon of Energy Resistance is recommended."},{"name":"Soul of Artifice","level":20,"description":"You have developed a mystical connection to your magic items, which you can draw on for aid.\n\nYou gain the following benefits:\n\nCheat Death. If you’re reduced to 0 Hit Points but not killed outright, you can disintegrate one Uncommon or Rare magic item created by your Replicate Magic Item feature, changing your Hit Points to 20 instead of 0.\n\nMagical Guidance. While you have Attunement to at least one magic item, you can add 1d6 to any ability check you make. You decide to add the die after rolling the d20, and you can use this benefit only once per turn."}]'::jsonb, TRUE, ARRAY['artificer', 'class', 'ua', 'ua1']::TEXT[]) ON CONFLICT (name) DO UPDATE SET source = EXCLUDED.source, description = EXCLUDED.description, primary_ability = EXCLUDED.primary_ability, saving_throws = EXCLUDED.saving_throws, hit_dice = EXCLUDED.hit_dice, weapon_proficiencies = EXCLUDED.weapon_proficiencies, armor_proficiencies = EXCLUDED.armor_proficiencies, tool_proficiencies = EXCLUDED.tool_proficiencies, skill_proficiencies = EXCLUDED.skill_proficiencies, class_table = EXCLUDED.class_table, features = EXCLUDED.features, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
