INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Boots of the Winding Path', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing these boots, you can take a Bonus Action to teleport up to 15 feet to an unoccupied space you can see. You must have occupied that space at some point during the current turn.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Mind Sharpener', 'Ring', 'Uncommon', 'No', 'Varies', 'The item has 4 charges. When you fail a Constitution saving throw to maintain Concentration, you can take a Reaction and expend 1 of the item’s charges to succeed instead. The item regains 1d4 expended charges daily at dawn.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Manifold Tool', 'Wondrous Item', 'Common', 'No', 'Varies', 'This tool takes the form of a wrench, screwdriver, or other basic tool. As a Magic action, you can touch the item and transform it into a type of Artisan’s Tools of your choice. Whatever form the tool takes, you have proficiency with it when you use it.', TRUE, ARRAY['item', 'ua', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Radiant Weapon', 'Weapon (Any Simple or Martial)', 'Rare', 'No', 'Varies', 'This magic weapon grants a +1 bonus to attack and damage rolls made with it. While holding it, you can take a Bonus Action to cause it to shed Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. You can extinguish the light as a Bonus Action.
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Helm of Awareness', 'Wondrous Item', 'Uncommon', 'No', 'Varies', 'While wearing this helmet, you have Advantage on Initiative rolls.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Repeating Shot', 'Weapon (Any Simple or Martial with the Ammunition Property)', 'Uncommon', 'No', 'Varies', 'This magic weapon grants a +1 bonus to attack and damage rolls made with it when it’s used to make a ranged attack roll, and it ignores the Loading property if it has it. If the weapon lacks ammunition, it produces its own, automatically creating one piece of magic ammunition when the wielder makes a ranged attack with it. The ammunition created by the weapon vanishes the instant after it hits or misses a target.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Repulsion Shield', 'Armor (Shield)', 'Uncommon', 'No', 'Varies', 'You gain a +1 bonus to Armor Class while wielding this shield. The shield has 4 charges. While holding it, you can take a Reaction immediately after being hit by a melee attack roll to expend 1 of the shield’s charges and push the attacker up to 15 feet away. The shield regains 1d4 expended charges daily at dawn.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Returning Weapon', 'Weapon (Any Simple or Martial with the Thrown Property)', 'Uncommon', 'No', 'Varies', 'This magic weapon grants a +1 bonus to attack and damage rolls made with it, and it returns to your hand immediately after it is used to make a ranged attack roll.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO ua.magic_items (name, type, rarity, attunement, price, description, legacy, tags) VALUES ('Spell-Refueling Ring', 'Ring', 'Uncommon', 'No', 'Varies', 'While wearing this ring, you can recover one expended spell slot as a Bonus Action. The recovered slot can be of level 3 or lower. Once used, the ring can’t be used again until the next dawn.', TRUE, ARRAY['item', 'ua', 'ua1', 'ua3']::TEXT[]) ON CONFLICT (name) DO UPDATE SET type = EXCLUDED.type, rarity = EXCLUDED.rarity, attunement = EXCLUDED.attunement, price = EXCLUDED.price, description = EXCLUDED.description, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
